#nullable enable

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;
using FastEndpoints;
using HappyPumi.Api.CloudSetup;
using HappyPumi.Api.Contracts;
using HappyPumi.Api.State;

namespace HappyPumi.Api.Endpoints.CloudSetup;

/// <summary>
/// CompleteOAuth — recovers the initiating provider from the session, exchanges the authorization code for
/// a credential, discovers the connected accounts, and persists them (credential write-only). Returns the
/// empty success contract; unconfigured providers persist an empty account list rather than failing.
/// </summary>
public sealed class CompleteOAuthEndpoint(
    ICloudSetupProviderRegistry registry, ICloudOAuthSessionStore sessions, IConnectedCloudAccountStore store)
    : EndpointWithoutRequest<CompleteOAuthResponse>
{
    public override void Configure()
    {
        Post("/api/esc/cloudsetup/{orgName}/oauth/complete");
        AllowAnonymous();
        Description(b => b
            .WithTags("CloudSetup")
            .WithSummary("CompleteOAuth")
            .WithDescription("Completes OAuth flow by exchanging authorization code for access token")
            .WithName("CompleteOAuth")
        );
    }

    public override async Task HandleAsync(CancellationToken ct)
    {
        var org = Route<string>("orgName")!;
        var body = await CloudSetupBody.ReadAsync(HttpContext, ct);
        var session = sessions.Get(CloudSetupBody.Str(body, "sessionID") ?? "");
        var provider = session is null ? null : registry.For(session.Provider);
        if (provider is not null)
            await ConnectAsync(org, provider, CloudSetupBody.Str(body, "code") ?? "", ct);
        await Send.OkAsync(new CompleteOAuthResponse(), ct);
    }

    private async Task ConnectAsync(string org, ICloudSetupProvider provider, string code, CancellationToken ct)
    {
        var cred = await provider.ExchangeCodeAsync(code, ct);
        var accounts = cred is null
            ? Array.Empty<CloudAccount>()
            : await provider.ListAccountsAsync(cred, ct);
        store.Upsert(org, provider.Key, accounts.Select(CloudAccountMapper.ToEntry).ToList(), cred?.AccessToken);
    }
}
